INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("青空の下で謁見", 91002, 2834, "フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", 2, 8, 40, 7, 5118061, 10118, 0, "フリーマーケット会場", 1, 20063115, "ペコリーヌとの出会い");
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("未来の騎空団\nマスコット？", 91002, 2835, "ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", 2, 8, 40, 7, 5118062, 10118, 0, "フリーマーケット会場", 1, 20063115, "マホとの出会い");
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("お嬢さまからの\n緊急依頼", 91002, 2837, "ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", 2, 8, 40, 7, 5118063, 10118, 0, "ランドソル市街地", 1, 20063115, "アキノとの出会い");
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("黄金色の悩みごと", 91002, 4108402, "ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", 2, 8, 40, 18, 5118064, 10118, 0, "フリーマーケット会場", 1, 20063115, "ジュンとの出会い");
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("白熱！　格闘大会！", 91002, 4107402, "フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", 2, 8, 40, 18, 5118065, 10118, 0, "フリーマーケット会場", 1, 20063115, "カオリとの出会い");
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("祭り太鼓はオーエドの華", 91002, 9000227, "太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", 2, 8, 40, 16, 5118066, 10118, 1, "オーエド町", 1, 20063115, "ニノンとの出会い");
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("人気者は遅れて\nやってくる", 91002, 2101181, "ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", 3, 8, 40, 19, 5118067, 10118, 0, "フリーマーケット会場", 1, 20063115, "スズナとの出会い");
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("巫女・ミーツ・魔法少女", 91002, 4109402, "ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", 3, 8, 40, 18, 5118068, 10118, 0, "ランドソル市街地", 1, 20063115, "ナナカとの出会い");
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ネズ耳は二度なくなる", 91002, 4305402, "ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", 3, 8, 40, 18, 5118069, 10118, 0, "フリーマーケット会場", 1, 20063115, "キャル＆コッコロとの出会い");
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("この出会いにカンパイ！", 91002, 4101402, "街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", 3, 8, 40, 18, 5118070, 10118, 0, "ランドソル市街地", 1, 20063115, "ユカリとの出会い");
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("陰陽アンサンブル", 91002, 4106402, "ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", 3, 8, 40, 18, 5118071, 10118, 0, "ランドソル市街地", 1, 20063115, "アオイとの出会い");
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("運試し十番勝負！", 91002, 2836, "ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", 3, 8, 40, 7, 5118072, 10118, 1, "フリーマーケット会場", 1, 20063115, "シノブとの出会い");
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("彼女たちの新たな日常", 0, 0, 0, 1, 0, 0, 0, 5118600, 10118, 0, 0, 0, 20063115, "オープニング");
